/**
 * ○○交通 需要予測・配車最適化コンソール — ドメインデータ
 *
 * 東京23区・横浜の主要エリア × 時間帯の予測需要、需給バランス、配車最適化レコメンド、
 * 需要要因（天候・イベント・曜日）。すべて関数を含まない素のデータなので Server Component
 * からそのまま読める（@gunjo/ui の関数 props は client 境界側で渡す）。
 */

/** 時間帯（朝→深夜）。ヒートマップの列・推移の x 軸に対応。 */
export const TIME_SLOTS = [
  { key: "early", label: "早朝", range: "5–7時" },
  { key: "amPeak", label: "朝ピーク", range: "7–10時" },
  { key: "midday", label: "日中", range: "10–16時" },
  { key: "pmPeak", label: "夕ピーク", range: "16–19時" },
  { key: "night", label: "夜間", range: "19–23時" },
  { key: "lateNight", label: "深夜", range: "23–5時" },
] as const

export type TimeSlotKey = (typeof TIME_SLOTS)[number]["key"]

/** エリア（営業エリア）。ヒートマップの行・需給バランスの地図に対応。 */
export interface AreaInfo {
  id: string
  /** 表示名 */
  label: string
  /** 待機場所の主軸（駅・ホテル・繁華街） */
  hub: string
}

export const AREAS: AreaInfo[] = [
  { id: "shibuya", label: "渋谷", hub: "渋谷駅・繁華街" },
  { id: "shinjuku", label: "新宿", hub: "新宿駅・歌舞伎町" },
  { id: "shinagawa", label: "品川", hub: "品川駅・ホテル群" },
  { id: "roppongi", label: "六本木", hub: "六本木交差点・クラブ街" },
  { id: "ginza", label: "銀座", hub: "銀座・有楽町" },
  { id: "haneda", label: "羽田", hub: "羽田空港 付け待ち" },
  { id: "yokohama", label: "横浜", hub: "横浜駅・みなとみらい" },
]

/**
 * エリア × 時間帯の予測需要（予測リクエスト件数）。
 * 値が大きいほど需要が濃い。ヒートマップのセル値。
 */
export const DEMAND_MATRIX: Record<string, Record<TimeSlotKey, number>> = {
  shibuya: { early: 40, amPeak: 210, midday: 180, pmPeak: 320, night: 410, lateNight: 290 },
  shinjuku: { early: 55, amPeak: 240, midday: 200, pmPeak: 300, night: 460, lateNight: 350 },
  shinagawa: { early: 130, amPeak: 280, midday: 150, pmPeak: 240, night: 190, lateNight: 90 },
  roppongi: { early: 30, amPeak: 90, midday: 110, pmPeak: 170, night: 280, lateNight: 380 },
  ginza: { early: 25, amPeak: 120, midday: 240, pmPeak: 230, night: 270, lateNight: 130 },
  haneda: { early: 220, amPeak: 260, midday: 210, pmPeak: 250, night: 230, lateNight: 70 },
  yokohama: { early: 60, amPeak: 190, midday: 170, pmPeak: 220, night: 250, lateNight: 140 },
}

/** ヒートマップ用にフラット化したセル配列（x=時間帯ラベル, y=エリアラベル）。 */
export interface DemandCell {
  areaId: string
  areaLabel: string
  slotKey: TimeSlotKey
  slotLabel: string
  value: number
}

export const DEMAND_CELLS: DemandCell[] = AREAS.flatMap((area) =>
  TIME_SLOTS.map((slot) => ({
    areaId: area.id,
    areaLabel: area.label,
    slotKey: slot.key,
    slotLabel: slot.label,
    value: DEMAND_MATRIX[area.id][slot.key],
  }))
)

/**
 * 需要の予測推移（本日の時間帯ごと、全エリア合算）。
 * 実績（確定済み）・予測（AI予測）・予測の上振れ/下振れ（信頼区間）を持つ。
 */
export interface TrendPoint {
  slotLabel: string
  /** 実績（観測済み）。未来の時間帯は null。 */
  actual: number | null
  /** AI 予測の中央値。 */
  forecast: number
  /** 信頼区間 下限（予測 −） */
  lower: number
  /** 信頼区間 上限（予測 +） */
  upper: number
}

export const DEMAND_TREND: TrendPoint[] = [
  { slotLabel: "早朝", actual: 560, forecast: 575, lower: 520, upper: 630 },
  { slotLabel: "朝ピーク", actual: 1390, forecast: 1410, lower: 1300, upper: 1520 },
  { slotLabel: "日中", actual: 1260, forecast: 1280, lower: 1180, upper: 1380 },
  { slotLabel: "夕ピーク", actual: null, forecast: 1730, lower: 1560, upper: 1900 },
  { slotLabel: "夜間", actual: null, forecast: 2090, lower: 1880, upper: 2300 },
  { slotLabel: "深夜", actual: null, forecast: 1470, lower: 1280, upper: 1660 },
]

/** 営業エリアごとの需給バランス（夕ピーク基準）。 */
export interface AreaBalance {
  areaId: string
  label: string
  hub: string
  /** 予測需要（台ベースに換算したリクエスト規模） */
  demand: number
  /** 現在の供給（稼働台数） */
  supply: number
  /**
   * 需給状態。
   * - shortage: 不足（需要 > 供給）→ 増車したい
   * - surplus: 供給過多（供給 > 需要）→ 配置転換できる
   * - balanced: 均衡
   */
  state: "shortage" | "surplus" | "balanced"
  /** 簡易な多角形ジオメトリ（ChoroplethMap 用・模式図）。経度緯度ではなく相対座標。 */
  geometry: { type: "Polygon"; coordinates: [number, number][][] }
}

/** 模式的なエリア配置（実地図ではなくレイアウト用の相対座標）。 */
const AREA_GEOMETRY: Record<string, [number, number][]> = {
  shibuya: [
    [10, 60], [28, 62], [30, 44], [12, 42],
  ],
  shinjuku: [
    [12, 86], [32, 88], [34, 66], [14, 64],
  ],
  shinagawa: [
    [44, 40], [62, 42], [64, 22], [46, 20],
  ],
  roppongi: [
    [34, 60], [50, 62], [52, 46], [36, 44],
  ],
  ginza: [
    [54, 64], [72, 66], [74, 48], [56, 46],
  ],
  haneda: [
    [66, 26], [88, 28], [90, 6], [68, 4],
  ],
  yokohama: [
    [40, 92], [62, 94], [64, 70], [42, 68],
  ],
}

export const AREA_BALANCES: AreaBalance[] = [
  { areaId: "shibuya", label: "渋谷", hub: "渋谷駅・繁華街", demand: 64, supply: 41, state: "shortage" },
  { areaId: "shinjuku", label: "新宿", hub: "新宿駅・歌舞伎町", demand: 60, supply: 48, state: "shortage" },
  { areaId: "shinagawa", label: "品川", hub: "品川駅・ホテル群", demand: 38, supply: 36, state: "balanced" },
  { areaId: "roppongi", label: "六本木", hub: "六本木交差点", demand: 52, supply: 33, state: "shortage" },
  { areaId: "ginza", label: "銀座", hub: "銀座・有楽町", demand: 30, supply: 47, state: "surplus" },
  { areaId: "haneda", label: "羽田", hub: "羽田空港 付け待ち", demand: 44, supply: 45, state: "balanced" },
  { areaId: "yokohama", label: "横浜", hub: "横浜駅・MM", demand: 41, supply: 39, state: "balanced" },
].map((b) => ({
  ...b,
  state: b.state as AreaBalance["state"],
  geometry: { type: "Polygon", coordinates: [AREA_GEOMETRY[b.areaId]] },
}))

/** 配車最適化の提案（優先度つき）。 */
export interface Recommendation {
  id: string
  /** 優先度 */
  priority: "high" | "medium" | "low"
  /** 対象エリア */
  area: string
  /** アクション要約（例：渋谷へ +5台） */
  action: string
  /** 何台、どこから/どこへ */
  detail: string
  /** 根拠（需要要因） */
  rationale: string
  /** 予測される効果（実車率や営収の改善見込み） */
  impact: string
  /** 推奨の信頼度（AI予測の確からしさ, 0–100） */
  confidence: number
}

export const RECOMMENDATIONS: Recommendation[] = [
  {
    id: "rec-shibuya-pm",
    priority: "high",
    area: "渋谷",
    action: "渋谷エリアへ +5台",
    detail: "近接待機 +3台 / 銀座から回送 +2台",
