"use client"

import * as React from "react"
import {
  IconCloudRain,
  IconMusic,
  IconSparkles,
  IconCalendarWeek,
  IconArrowRight,
  IconCheck,
  IconMapPin,
} from "@tabler/icons-react"

import {
  HeatmapChart,
  type HeatmapChartCell,
  ChoroplethMap,
  type ChoroplethMapRegion,
  LineChart,
  ChartLegend,
  Card,
  CardHeader,
  CardTitle,
  CardDescription,
  CardContent,
  ListCard,
  FilterChips,
  Badge,
  Button,
  Select,
  Meter,
  Delta,
  Separator,
  Alert,
  AlertTitle,
  AlertDescription,
  formatNumber,
  type ChartColor,
} from "@gunjo/ui"

import {
  AREAS,
  TIME_SLOTS,
  type TimeSlotKey,
  DEMAND_CELLS,
  DEMAND_TREND,
  AREA_BALANCES,
  type AreaBalance,
  RECOMMENDATIONS,
  type Recommendation,
  DEMAND_FACTORS,
  type DemandFactor,
} from "./data"

/* ------------------------------------------------------------------ */
/* helpers                                                            */
/* ------------------------------------------------------------------ */

const fmtCount = (n: number) => `${formatNumber(n)} 件`

const PRIORITY_META: Record<
  Recommendation["priority"],
  { label: string; severity: "critical" | "warning" | "info"; badge: "destructive" | "warning" | "info" }
> = {
  high: { label: "優先度 高", severity: "critical", badge: "destructive" },
  medium: { label: "優先度 中", severity: "warning", badge: "warning" },
  low: { label: "優先度 低", severity: "info", badge: "info" },
}

const BALANCE_META: Record<
  AreaBalance["state"],
  { label: string; color: ChartColor; badge: "destructive" | "info" | "success" }
> = {
  shortage: { label: "不足", color: "destructive", badge: "destructive" },
  surplus: { label: "供給過多", color: "info", badge: "info" },
  balanced: { label: "均衡", color: "success", badge: "success" },
}

const FACTOR_ICON: Record<DemandFactor["kind"], React.ReactNode> = {
  weather: <IconCloudRain className="size-4" aria-hidden="true" />,
  event: <IconMusic className="size-4" aria-hidden="true" />,
  weekday: <IconCalendarWeek className="size-4" aria-hidden="true" />,
}

/* ------------------------------------------------------------------ */
/* component                                                          */
/* ------------------------------------------------------------------ */

export function DemandConsole() {
  // 絞り込み: 時間帯（FilterChips 単一選択）。"all" = 終日。
  const [slot, setSlot] = React.useState<TimeSlotKey | "all">("pmPeak")
  // ヒートマップで選択中のセル（エリア×時間帯）。
  const [selected, setSelected] = React.useState<{ areaLabel: string; slotLabel: string; value: number } | null>(null)
  // 需給バランス地図で選択中のエリア。
  const [selectedArea, setSelectedArea] = React.useState<string>("shibuya")
  // 適用済みレコメンド。
  const [applied, setApplied] = React.useState<Set<string>>(new Set())

  /* --- 時間帯フィルタ chips --- */
  const slotChips = React.useMemo(
    () => [
      { value: "all", label: "終日" },
      ...TIME_SLOTS.map((s) => ({ value: s.key, label: `${s.label}` })),
    ],
    []
  )

  /* --- ヒートマップ data --- */
  const heatmapCells: HeatmapChartCell[] = React.useMemo(
    () =>
      DEMAND_CELLS.map((c) => ({
        x: c.slotLabel,
        y: c.areaLabel,
        value: c.value,
        // 選択中の時間帯列以外は淡くトーンを落として「今見ている時間帯」を強調
        color: slot === "all" || c.slotKey === slot ? "primary" : "muted",
        description: `予測 ${fmtCount(c.value)}`,
      })),
    [slot]
  )

  const xLabels = TIME_SLOTS.map((s) => s.label)
  const yLabels = AREAS.map((a) => a.label)

  /* --- 推移: 予測 / 実績 / 信頼区間（上下限を別系列で表現） --- */
  const trendSeries = React.useMemo(
    () => [
      {
        label: "予測（中央値）",
        color: "primary" as ChartColor,
        data: DEMAND_TREND.map((p) => ({ label: p.slotLabel, value: p.forecast })),
      },
      {
        label: "実績",
        color: "success" as ChartColor,
        // 実績は未来時間帯で null → 系列が途切れる
        data: DEMAND_TREND.filter((p) => p.actual !== null).map((p) => ({
          label: p.slotLabel,
          value: p.actual as number,
        })),
      },
      {
        label: "信頼区間 上限",
        color: "muted" as ChartColor,
        data: DEMAND_TREND.map((p) => ({ label: p.slotLabel, value: p.upper })),
      },
      {
        label: "信頼区間 下限",
        color: "muted" as ChartColor,
        data: DEMAND_TREND.map((p) => ({ label: p.slotLabel, value: p.lower })),
      },
    ],
    []
  )

  /* --- 需給バランス: ChoroplethMap regions --- */
  const regions: ChoroplethMapRegion[] = React.useMemo(
    () =>
      AREA_BALANCES.map((b) => ({
        id: b.areaId,
        label: b.label,
        // 「不足の深さ」を値に：需要−供給。マイナス（過多）は0でクランプして“不足の濃さ”を塗る
        value: Math.max(b.demand - b.supply, 0),
        color: BALANCE_META[b.state].color,
        geometry: b.geometry,
        description: `需要${b.demand} / 供給${b.supply}・${BALANCE_META[b.state].label}`,
      })),
    []
  )

  const selectedBalance = AREA_BALANCES.find((b) => b.areaId === selectedArea) ?? AREA_BALANCES[0]

  const shortageCount = AREA_BALANCES.filter((b) => b.state === "shortage").length

  const toggleApply = (id: string) =>
    setApplied((prev) => {
      const next = new Set(prev)
      if (next.has(id)) next.delete(id)
      else next.add(id)
      return next
    })

  return (
    <div className="space-y-6">
      {/* 絞り込みバー */}
      <Card className="p-4">
        <div className="flex flex-col gap-4 lg:flex-row lg:items-end lg:justify-between">
          <div className="min-w-0 flex-1">
            <p className="mb-2 text-xs font-medium text-muted-foreground">時間帯で絞り込み</p>
            <FilterChips
              items={slotChips}
              value={slot}
              onValueChange={(v) => setSlot(v as TimeSlotKey | "all")}
              aria-label="時間帯の絞り込み"
            />
          </div>
          <div className="flex shrink-0 flex-wrap items-end gap-3">
            <Select label="日付" defaultValue="today" className="w-40">
              <option value="today">本日 6/28（金）</option>
              <option value="tomorrow">明日 6/29（土）</option>
              <option value="weekend">今週末</option>
            </Select>
            <Select label="エリア群" defaultValue="all" className="w-40">
              <option value="all">全エリア</option>
              <option value="tokyo23">東京23区</option>
              <option value="yokohama">横浜</option>
            </Select>
            <Select label="予測モデル" defaultValue="ai-v3" className="w-44">
              <option value="ai-v3">AI予測 v3（標準）</option>
              <option value="ai-v3-rain">AI予測 v3 + 天候補正</option>
              <option value="baseline">前年同曜日 ベースライン</option>
            </Select>
          </div>
        </div>
      </Card>

      {/* メイン: ヒートマップ（中央・大）＋ 推移 */}
      <div className="grid grid-cols-1 gap-6 xl:grid-cols-[1.55fr_1fr]">
        {/* エリア×時間帯 需要ヒートマップ */}
        <Card className="min-w-0 p-0">
          <CardHeader className="p-5 pb-3">
            <div className="flex flex-wrap items-start justify-between gap-3">
              <div className="min-w-0">
                <CardTitle as="h2" className="text-base">
                  エリア × 時間帯 需要ヒートマップ
                </CardTitle>
                <CardDescription className="mt-1">
                  色が濃いほど予測需要が高い。セルを選ぶと配置の根拠を確認できます。
                </CardDescription>
              </div>
              <div className="flex items-center gap-2 text-xs text-muted-foreground">
                <span>薄い</span>
                <span
                  className="h-3 w-24 rounded-full"
                  style={{
                    background:
                      "linear-gradient(to right, hsl(var(--primary)/0.12), hsl(var(--primary)))",
                  }}
                  aria-hidden="true"
                />
                <span>濃い（需要 大）</span>
              </div>
            </div>
          </CardHeader>
          <CardContent className="p-5 pt-2">
            <HeatmapChart
              data={heatmapCells}
              xLabels={xLabels}
              yLabels={yLabels}
              showValues
              formatValue={(v) => formatNumber(v)}
              selectedCell={
                selected ? { x: selected.slotLabel, y: selected.areaLabel } : undefined
              }
              onCellSelect={(cell) =>
                setSelected({ areaLabel: cell.y, slotLabel: cell.x, value: cell.value })
              }
              aria-label="エリア別・時間帯別の予測需要ヒートマップ"
            />
            {selected ? (
              <div className="mt-4 flex flex-wrap items-center gap-x-4 gap-y-2 rounded-md border bg-muted/30 px-4 py-3 text-sm">
                <span className="inline-flex items-center gap-1.5 font-medium">
                  <IconMapPin className="size-4 text-muted-foreground" aria-hidden="true" />
                  {selected.areaLabel} ・ {selected.slotLabel}
                </span>
                <span className="text-muted-foreground">
                  予測需要 <strong className="text-foreground tabular-nums">{fmtCount(selected.value)}</strong>
                </span>
                <span className="text-muted-foreground">
                  {selected.value >= 300
                    ? "高需要帯：増車・付け待ち強化を推奨"
                    : selected.value >= 150
                    ? "中需要帯：現状配置で対応可"
                    : "低需要帯：流し中心で充足"}
                </span>
              </div>
            ) : (
              <p className="mt-4 text-xs text-muted-foreground">
                セルを選択すると、そのエリア・時間帯の予測詳細を表示します。
              </p>
            )}
          </CardContent>
        </Card>

        {/* 需要の予測推移 */}
        <Card className="min-w-0 p-0">
          <CardHeader className="p-5 pb-2">
            <CardTitle as="h2" className="text-base">
              需要の予測推移（本日・全エリア）
            </CardTitle>
            <CardDescription className="mt-1">
              実績は確定分まで。以降は AI 予測（中央値）と信頼区間。
            </CardDescription>
          </CardHeader>
          <CardContent className="p-5 pt-2">
            <LineChart
              variant="area"
              series={trendSeries}
              showDots
              showGrid
              formatValue={(v) => formatNumber(v)}
              aria-label="本日の需要予測推移（実績・予測・信頼区間）"
            />
            <ChartLegend
              className="mt-3"
              variant="horizontal"
              items={[
                { label: "予測（中央値）", color: "primary" },
                { label: "実績", color: "success" },
                { label: "信頼区間（上限/下限）", color: "muted" },
              ]}
            />
            <Separator className="my-4" />
            <div className="grid grid-cols-2 gap-3 text-sm">
              <div>
                <p className="text-xs text-muted-foreground">夜間ピーク 予測</p>
                <p className="text-lg font-semibold tabular-nums">2,090 件</p>
                <p className="text-xs text-muted-foreground">信頼区間 1,880–2,300</p>
              </div>
              <div>
                <p className="text-xs text-muted-foreground">日中 予測 vs 実績</p>
                <p className="inline-flex items-baseline gap-1.5 text-lg font-semibold tabular-nums">
                  1,280
                  <Delta
                    value={20}
                    className="text-sm"
                    labels={{ positive: "上振れ", negative: "下振れ", zero: "一致" }}
                    showLabel
                  />
                </p>
                <p className="text-xs text-muted-foreground">実績 1,260 件に対し +20</p>
              </div>
            </div>
          </CardContent>
        </Card>
      </div>

      {/* 需給バランス（地図）＋ 配車最適化レコメンド */}
      <div className="grid grid-cols-1 gap-6 xl:grid-cols-[1fr_1fr]">
        {/* エリア別 需給バランス */}
        <Card className="min-w-0 p-0">
          <CardHeader className="p-5 pb-2">
            <div className="flex flex-wrap items-start justify-between gap-3">
              <div className="min-w-0">
                <CardTitle as="h2" className="text-base">
                  エリア別 需給バランス（夕ピーク）
                </CardTitle>
                <CardDescription className="mt-1">
                  色が濃い＝不足が深い。エリアを選ぶと需給ギャップを表示します。
                </CardDescription>
              </div>
              <Badge variant="destructive">{shortageCount} エリアで不足</Badge>
            </div>
          </CardHeader>
          <CardContent className="p-5 pt-2">
            <ChoroplethMap
              regions={regions}
              selectedId={selectedArea}
              onRegionSelect={(_region, id) => setSelectedArea(id)}
              showRanking
              rankingLimit={5}
              rankLabel="不足ランク"
              selectedLabel="選択エリア（不足台数）"
              formatValue={(v) => `${formatNumber(v)} 台不足`}
              aria-label="エリア別の需給ギャップ（不足台数）マップ"
            />
            <Separator className="my-4" />
            <div className="rounded-md border bg-card p-4">
              <div className="flex items-center justify-between gap-3">
                <div className="min-w-0">
                  <p className="truncate text-sm font-semibold">
                    {selectedBalance.label}
                    <span className="ml-2 align-middle">
                      <Badge variant={BALANCE_META[selectedBalance.state].badge}>
                        {BALANCE_META[selectedBalance.state].label}
                      </Badge>
                    </span>
                  </p>
                  <p className="truncate text-xs text-muted-foreground">{selectedBalance.hub}</p>
                </div>
                <Delta
                  value={selectedBalance.supply - selectedBalance.demand}
                  format={(v) => `${formatNumber(Math.abs(v))}台`}
                  labels={{ positive: "供給過多", negative: "不足", zero: "均衡" }}
                  showLabel
                />
              </div>
              <div className="mt-3 grid gap-3 sm:grid-cols-2">
                <Meter
                  label="予測需要"
                  value={selectedBalance.demand}
                  max={80}
                  unit="台"
                  tone="primary"
                  size="sm"
                />
                <Meter
                  label="現在の供給（稼働）"
                  value={selectedBalance.supply}
                  max={80}
                  target={selectedBalance.demand}
                  direction="higher-is-better"
                  unit="台"
                  size="sm"
                />
              </div>
            </div>
          </CardContent>
        </Card>

        {/* 配車最適化レコメンド */}
        <Card className="min-w-0 p-0">
          <CardHeader className="p-5 pb-2">
            <div className="flex flex-wrap items-start justify-between gap-3">
              <div className="min-w-0">
                <CardTitle as="h2" className="text-base">
                  配車最適化レコメンド
                </CardTitle>
                <CardDescription className="mt-1">
                  優先度順。根拠と効果を確認して配置を適用します。
                </CardDescription>
              </div>
              <Badge variant="outline">{applied.size} / {RECOMMENDATIONS.length} 適用</Badge>
            </div>
          </CardHeader>
          <CardContent className="space-y-2.5 p-5 pt-2">
            {RECOMMENDATIONS.map((rec) => {
              const meta = PRIORITY_META[rec.priority]
              const isApplied = applied.has(rec.id)
              return (
                <ListCard
                  key={rec.id}
                  severity={meta.severity}
                  selected={isApplied}
                  leading={
                    <span className="flex size-9 items-center justify-center rounded-md bg-primary-subtle text-primary-subtle-foreground">
                      <IconArrowRight className="size-5" aria-hidden="true" />
                    </span>
                  }
                  title={
                    <span className="flex flex-wrap items-center gap-2">
                      {rec.action}
                      <Badge variant={meta.badge}>{meta.label}</Badge>
                    </span>
                  }
                  description={
                    <span className="block space-y-1">
                      <span className="block">{rec.detail}</span>
                      <span className="block text-xs">
                        <span className="font-medium text-foreground">根拠：</span>
                        {rec.rationale}
                      </span>
                      <span className="block text-xs text-success-strong">{rec.impact}</span>
                    </span>
                  }
                  tags={
                    <>
                      <Badge variant="secondary" icon={<IconSparkles />}>
                        信頼度 {rec.confidence}%
                      </Badge>
                      <Badge variant="outline">{rec.area}</Badge>
                    </>
                  }
                  meta={
                    <Button
                      size="sm"
                      variant={isApplied ? "success" : "primary"}
                      onClick={() => toggleApply(rec.id)}
                      aria-pressed={isApplied}
                    >
                      {isApplied ? (
                        <>
                          <IconCheck className="size-4" aria-hidden="true" /> 適用済み
                        </>
                      ) : (
                        "配置を適用"
                      )}
                    </Button>
                  }
                  trailing={null}
                />
              )
            })}
          </CardContent>
        </Card>
      </div>

      {/* 需要の要因 */}
      <Card className="min-w-0 p-0">
        <CardHeader className="p-5 pb-2">
          <CardTitle as="h2" className="text-base">
            需要の要因（天候・イベント・曜日）
          </CardTitle>
          <CardDescription className="mt-1">
            予測に織り込まれている外部要因。配置判断の背景として確認します。
          </CardDescription>
        </CardHeader>
        <CardContent className="p-5 pt-2">
          <div className="grid grid-cols-1 gap-3 sm:grid-cols-2 xl:grid-cols-4">
            {DEMAND_FACTORS.map((f) => (
              <Alert key={f.id} variant={f.kind === "weather" ? "info" : "warning"}>
                {FACTOR_ICON[f.kind]}
                <AlertTitle as="h3" className="flex items-center justify-between gap-2">
                  <span className="truncate">{f.title}</span>
                  <Delta
                    value={f.impactPct}
                    format={(v) => `${formatNumber(v, { signed: true })}%`}
                    hideArrow
                    className="shrink-0 text-sm"
                  />
                </AlertTitle>
                <AlertDescription>
                  <span className="block">{f.detail}</span>
                  <span className="mt-1 block text-[11px] opacity-80">対象：{f.areas}</span>
                </AlertDescription>
              </Alert>
            ))}
          </div>
        </CardContent>
      </Card>
    </div>
  )
}
